go/go闭包.html.body:
闭包
闭包捕获的是当前变量的引用。
package main

import (
    "fmt"
    "time"
)

var values = [5]int{10, 11, 12, 13, 14}

func main() {
    // 版本A:
    for ix := range values { // ix是索引值
        func() {
            fmt.Print(ix, " ")
        }() // 调用闭包打印每个索引值
    }
    fmt.Println()
    // 版本B: 和A版本类似，但是通过调用闭包作为一个协程
    for ix := range values {
        go func() {
            fmt.Print(ix, " ")
        }()
    }
    fmt.Println()
    time.Sleep(5e9)
    // 版本C: 正确的处理方式
    for ix := range values {
        go func(ix interface{}) {
            fmt.Print(ix, " ")
        }(ix)
    }
    fmt.Println()
    time.Sleep(5e9)
    // 版本D: 输出值:
    for ix := range values {
        val := values[ix]
        go func() {
            fmt.Print(val, " ")
        }()
    }
    time.Sleep(1e9)
}
版本A
使用闭包打印每个索引值。0 1 2 3 4
版本B
B的循环中，ix实际上是一个单变量，表示每个数组元素的索引值，因为这些闭包只绑定到一个变量,当运行代码时，不会看到每个元素的索引值，协程可能在循环结束时还没开始执行。
版本C
调用每个闭包是将ix作为参数传递给闭包，ix在每次循环的时都会被重新赋值，并将每个协程的ix放置在栈中，所以当协程最终被执行时，每个索引值对协程都是可用的，但顺序可能不同，取决于哪个协程开始执行。
版本D
D中的变量声明在循环内部，在每次循环时，这些变量相互之间不共享，所以这些变量可以单独被每个闭包使用。

go/go embed.html.body:
embed
1、嵌入

对于单个文件，支持嵌入为字符串和byte slice
对于多个文件和文件夹，支持嵌入为新的文件系统Fs
导入embed包，即使无显式使用
go:embed指令用来嵌入，必须紧跟着嵌入后的变量名
只支持嵌入为string，byte slice和embed.FS三种类型，这三种的别名和命名类型都不可以

示例
1）嵌入为字符串
package main

import (
    _ "embed"
    "fmt"
)

//go:embed hello.txt
var s string

func main() {
    fmt.Println(s)
}

2）嵌入为slice
package main

import (
    _ "embed"
    "fmt"
)

//go:embed hello.txt
var b []byte

func main() {
    fmt.Println(b)
}

3）嵌入为fs.FS
嵌入为一个文件
package main

import (
    "embed"
    "fmt"
)

//go:embed hello.txt
var f embed.FS

func main() {
    data, _ := f.ReadFile("hello.txt")
    fmt.Println(string(data))
}

嵌入多个文件
package main

import (
    "embed"
    "fmt"
)

//go:embed hello.txt
//go:embed hello2.txt
var f embed.FS

func main() {
    data, _ := f.ReadFile("hello.txt")
    fmt.Println(string(data))
    data, _ = f.ReadFile("hello2.txt")
    fmt.Println(string(data))
}

嵌入子文件夹下的文件
package main

import (
    "embed"
    "fmt"
)

//go:embed p/hello.txt
//go:embed p/hello2.txt
var f embed.FS

func main() {
    data, _ := f.ReadFile("p/hello.txt")
    fmt.Println(string(data))
    data, _ = f.ReadFile("p/hello2.txt")
    fmt.Println(string(data))
}

4）同一个文件嵌入为多个变量
package main

import (
    _ "embed"
    "fmt"
)

//go:embed hello.txt
var s string

//go:embed hello.txt
var s2 string

func main() {
    fmt.Println(s)

    fmt.Println(s2)
}

5）exported 和 unexported
package main

import (
    _ "embed"
    "fmt"
)

//go:embed hello.txt
var s string

//go:embed hello2.txt
var S string

func main() {
    fmt.Println(s)

    fmt.Println(S)
}

6）package级别的变量和局部变量都支持
package main

import (
    _ "embed"
    "fmt"
)

func main() {
    //go:embed hello.txt
    var s string

    //go:embed hello.txt
    var s2 string

    fmt.Println(s, s2)
}

注意：s和s2的值编译期就已经确定了，即使运行时更改了文件，也不会改变和影响s和s2的值。
2、只读
嵌入的内容是只读的。在编译期嵌入文件的内容是什么，那么运行时内容也就是什么。
FS文件系统只提供了打开和读取的方法，并没有写入的方法，FS的实例是线程安全的，多个goroutine可以并发使用
3、go:embed指令
go:embed指令支持嵌入多个文件
package main

import (
    "embed"
    "fmt"
)

//go:embed hello.txt hello2.txt
var f embed.FS

func main() {
    data, _ := f.ReadFile("hello.txt")
    fmt.Println(string(data))

    data, _ = f.ReadFile("hello2.txt")
    fmt.Println(string(data))
}

支持文件夹
package main

import (
    "embed"
    "fmt"
)

//go:embed p
var f embed.FS

func main() {
    data, _ := f.ReadFile("p/hello.txt")
    fmt.Println(string(data))

    data, _ = f.ReadFile("p/hello2.txt")
    fmt.Println(string(data))
}

使用的是相对路径
package main

import (
    "embed"
    "fmt"
)

//go:embed "he llo.txt" `hello-2.txt`
var f embed.FS

func main() {
    data, _ := f.ReadFile("he llo.txt")
    fmt.Println(string(data))
}

匹配模式
package main

import (
    "embed"
    "fmt"
)

//go:embed p/*
var f embed.FS

func main() {
    data, _ := f.ReadFile("p/.hello.txt")
    fmt.Println(string(data))

    data, _ = f.ReadFile("p/q/.hi.txt") // 没有嵌入 p/q/.hi.txt
    fmt.Println(string(data))
}

嵌入和嵌入模式不支持绝对路径，不支持路径中包含.和..，如果想嵌入go源文件所在的路径，使用*
package main

import (
    "embed"
    "fmt"
)

//go:embed *
var f embed.FS

func main() {
    data, _ := f.ReadFile("hello.txt")
    fmt.Println(string(data))

    data, _ = f.ReadFile(".hello.txt")
    fmt.Println(string(data))
}

4、文件系统
打开文件
package main

import (
    "embed"
    "fmt"
)

//go:embed *
var f embed.FS

func main() {
    helloFile, _ := f.Open("hello.txt")
    stat, _ := helloFile.Stat()
    fmt.Println(stat.Name(), stat.Size())
}

遍历一个文件下的文件和文件夹信息：
package main

import (
    "embed"
    "fmt"
)

//go:embed *
var f embed.FS

func main() {
    dirEntries, _ := f.ReadDir("p")
    for _, de := range dirEntries {
        fmt.Println(de.Name(), de.IsDir())
    }
}

可以返回子文件夹作为新的文件系统
package main

import (
    "embed"
    "fmt"
    "io/fs"
    "io/ioutil"
)

//go:embed *
var f embed.FS

func main() {
    ps, _ := fs.Sub(f, "p")
    hi, _ := ps.Open("q/hi.txt")
    data, _ := ioutil.ReadAll(hi)
    fmt.Println(string(data))
}

go/interface.html.body:
接口
1、鸭子类型
如果某个东西长得像鸭子，像鸭子一样游泳，像鸭子一样嘎嘎叫，那它就可以被看成是一只鸭子。
所谓的鸭子类型就是动态编程语言的一种对象推断策略，它更关注对象能如何被使用，而不是对象的类型本身。
Go语言作为一门静态语言，它通过接口的方式完美支持鸭子类型。
静态语言诸如java，c++，必须要显式地声明实现了某个接口，之后才能用在任何需要这个接口的地方。
静态语言在编译期间就能发现类型不匹配的错误，不像动态语言，必须要运行到那一行代码才会报错。静态语言要求程序员在编码阶段就要按照规定来编写程序，为每个变量规定数据类型，这在某种程度上，加大了工作量，也加长了代码量。动态语言则没有这些要求，可以让人更专注在业务上，代码也更短，写起来更快。
2、使用场景
空接口：可以接收任意类型
1）作为函数的参数，可以接收任意类型，可以编写较为通用的函数。
func (p *pp) printArg(arg any, verb rune) {
    p.arg = arg
    p.value = reflect.Value{}

    if arg == nil {
       switch verb {
       case 'T', 'v':
          p.fmt.padString(nilAngleString)
       default:
          p.badVerb(verb)
       }
       return
    }

    // Special processing considerations.
    // %T (the value's type) and %p (its address) are special; we always do them first.
    switch verb {
    case 'T':
       p.fmt.fmtS(reflect.TypeOf(arg).String())
       return
    case 'p':
       p.fmtPointer(reflect.ValueOf(arg), 'p')
       return
    }

    // Some types can be done without reflection.
    switch f := arg.(type) {
    case bool:
       p.fmtBool(f, verb)
    case float32:
       p.fmtFloat(float64(f), 32, verb)
    case float64:
       p.fmtFloat(f, 64, verb)
    case complex64:
       p.fmtComplex(complex128(f), 64, verb)
    case complex128:
       p.fmtComplex(f, 128, verb)
    case int:
       p.fmtInteger(uint64(f), signed, verb)
    case int8:
       p.fmtInteger(uint64(f), signed, verb)
    case int16:
       p.fmtInteger(uint64(f), signed, verb)
    case int32:
       p.fmtInteger(uint64(f), signed, verb)
    case int64:
       p.fmtInteger(uint64(f), signed, verb)
    case uint:
       p.fmtInteger(uint64(f), unsigned, verb)
    case uint8:
       p.fmtInteger(uint64(f), unsigned, verb)
    case uint16:
       p.fmtInteger(uint64(f), unsigned, verb)
    case uint32:
       p.fmtInteger(uint64(f), unsigned, verb)
    case uint64:
       p.fmtInteger(f, unsigned, verb)
    case uintptr:
       p.fmtInteger(uint64(f), unsigned, verb)
    case string:
       p.fmtString(f, verb)
    case []byte:
       p.fmtBytes(f, verb, "[]byte")
    case reflect.Value:
       // Handle extractable values with special methods
       // since printValue does not handle them at depth 0.
       if f.IsValid() && f.CanInterface() {
          p.arg = f.Interface()
          if p.handleMethods(verb) {
             return
          }
       }
       p.printValue(f, verb, 0)
    default:
       // If the type is not simple, it might have methods.
       if !p.handleMethods(verb) {
          // Need to use reflection, since the type had no
          // interface methods that could be used for formatting.
          p.printValue(reflect.ValueOf(f), verb, 0)
       }
    }
}

2）作为函数返回值，当不确定函数可能返回的类型时，可以使用空接口作为函数的返回值。
3）在数据结构中存储任意类型.
4）类型断言
注意：虽然空接口可以用来存储任何类型的值，但是过度使用空接口会使代码失去类型信息，增加运行时错误的风险，也会使代码更难理解和维护。
带方法的接口
1）实现多态。
2）解循环引用。在go中，当两个包互相引用对方的类型或者方法时，会导致包循环引用，从而编译不通过。
package packageA

import (
    "fmt"
    "dev.roombox.xdf.cn/galaxy/benchnet/projects/test/packageB"
)

type A struct {
}

func (a *A) AMethod() {
    fmt.Println("a method")
}

func UseBMethod(b *packageB.B) {
    b.BMethod()
}

package packageB

import (
    "dev.roombox.xdf.cn/galaxy/benchnet/projects/test/packageA"
    "fmt"
)

type B struct {
}

func (b *B) BMethod() {
    a := &packageA.A{}
    a.AMethod()
    fmt.Println("b method")
}

这里可以考虑使用接口进行解引用
package packageA

import (
    "fmt"
)

type MyInterfaceB interface {
    BMethod()
}

type A struct {
}

func (a *A) AMethod() {
    fmt.Println("a method")
}

func UseBMethod(b MyInterfaceB) {
    b.BMethod()
}

3、值接收者和指针接收者
1）在调用方法的时候，值类型既可以调用值接收者的方法，也可以调用指针接收者的方法；指针类型既可以调用指针接收者的方法，也可以调用值接收者的方法。
编译器会在背后做一些工作。




值接收者
指针接收者




值类型调用者
方法会使用调用者的一个副本，类似于传值。
使用值的引用来调用方法，相当于对值取地址，然后调用方法。


指针类型调用者
指针被解引用为值，相当于间接引用然后调用方法。
也是传值，方法里的操作会影响到调用者，类似于指针传参，拷贝了一份指针。



2）在实现接口的时候，接收者如果是值类型，相当于自动实现了接收者是指针类型的方法，而接收者是指针类型，则不会自动生成对应接收者是值类型的方法。




结构体实现接口
结构体指针实现接口




结构体初始化变量
通过
不通过


结构体指针初始化变量
通过
通过




当实现接口的类型和初始化变量时返回的类型是相同的，代码一定会通过编译。

当方法的接收者是值类型，而初始化的变量是指针类型时，作为指针的变量进行拷贝会得到一个相同的指针，能够隐式地对变量进行解引用获取到指向的值，然后再执行对应的方法。

当方法的接收者是指针类型，而初始化的变量是值类型时，作为值的变量进行拷贝得到一个全新的值，但是方法的接收者作为方法的第一个参数需要的是一个指针，编译器不会无中生有创建一个新的指针，即使编译器可以创建新的指针，这个指针指向的也不是最初调用该方法的结构体。



​    接收者是指针类型的方法，很可能在方法中会对接收者的属性进行更改操作，从而影响接收者；而对于接收者是值类型的方法，在方法中不会对接收者本身产生影响。所以当实现了一个接收者是值类型的方法，就可以自动生成一个接收者是对应指针类型的方法，在方法中不会对接收者本身产生影响。但是当实现了一个接收者是指针类型的方法，如果此时自动生成一个接收者是值类型的方法，原本希望对接收者的改变，现在无法实现，因为值类型会产生一个拷贝，不会真正影响调用者。
3）两者何时使用
使用指针作为方法接收者的理由：

方法能够修改接收者指向的值。
避免在每次调用方法时复制该值，在值的类型为大型结构体时，这样做更加高效。

是使用值接收者还是指针接收者，不是由该方法是否修改了调用者来决定，而是应该基于该类型的本质。
4、接口源码分析
非空接口
type iface struct {
    tab  *itab          // 表示一个接口类型以及赋值给这个类型的实体类型
    data unsafe.Pointer // 指向具体的值，一般而言指向堆内存
}

type itab struct {
    inter *interfacetype // 接口类型
    _type *_type         // 具体类型
    hash  uint32         // copy of _type.hash. Used for type switches. 快速判等
    _     [4]byte        // 预留
    // 和接口方法对应的具体类型的方法的地址
    // 这里仅放置具体类型和接口相关的方法
    fun [1]uintptr // variable sized. fun[0]==0 means _type does not implement inter.
}

type interfacetype struct {
    typ     _type
    pkgpath name      // 接口所在的包名
    mhdr    []imethod // 接口定义的函数列表
}


空接口
type eface struct {
    _type *_type         // 表示空接口所承载的实体类型
    data  unsafe.Pointer // 指向具体的值
}
核心结构体
type _type struct {
    // 类型大小
    size    uintptr
    ptrdata uintptr // size of memory prefix holding all pointers
    hash    uint32  // 类型的hash值
    tflag   tflag   // todo 反射相关
    // 内存对齐
    align      uint8
    fieldAlign uint8
    kind       uint8 // 类型类别
    // function for comparing objects of this type
    // (ptr to object A, ptr to object B) -> ==?
    equal func(unsafe.Pointer, unsafe.Pointer) bool // 对象快速判等函数
    // gcdata stores the GC type data for the garbage collector.
    // If the KindGCProg bit is set in kind, gcdata is a GC program.
    // Otherwise it is a ptrmask bitmap. See mbitmap.go for details.
    // gc相关
    gcdata    *byte
    str       nameOff
    ptrToThis typeOff
}

接口类型和nil比较
接口值的零值是指动态类型和动态值都为nil。当且仅当这两部分的值都为nil的情况下，这个接口的值才会被认为是nil。
打印出接口的动态类型和值
package main

import (
    "unsafe"
    "fmt"
)

// 采用自定义iface结构体
type iface struct {
    itab, data uintptr
}

func main() {
    var a interface{} = nil

    var b interface{} = (*int)(nil)

    x := 5
    var c interface{} = (*int)(&x)

  // 强制解引用
    ia := *(*iface)(unsafe.Pointer(&a))
    ib := *(*iface)(unsafe.Pointer(&b))
    ic := *(*iface)(unsafe.Pointer(&c))

    fmt.Println(ia, ib, ic)

    fmt.Println(*(*int)(unsafe.Pointer(ic.data)))
}

编译器会检查类型是否实现了接口
var _ io.Writer = (*myWriter)(nil)
上述赋值语句会发生隐式类型转换，在转换的过程中，编译器会检测等号右边的类型是否实现了等号左边接口所规定的函数。
接口的构造过程
源码中会调用convert函数，它会构造出一个interface。
// 组装iface
func convT2I64(tab *itab, elem unsafe.Pointer) (i iface) {
    t := tab._type

    //...

    var x unsafe.Pointer
    if *(*uint64)(elem) == 0 {
        x = unsafe.Pointer(&zeroVal[0])
    } else {
        x = mallocgc(8, t, false)
        *(*uint64)(x) = *(*uint64)(elem)
    }
    i.tab = tab
    i.data = x
    return
}

打印接口的hash值
// 原理：定义一个山寨版的iface和itab，通过强制类型转换可以读取出想要的值。
type iface struct {
    tab  *itab
    data unsafe.Pointer
}
type itab struct {
    inter uintptr
    _type uintptr
    link uintptr
    hash  uint32
    _     [4]byte
    fun   [1]uintptr
}

func main() {
    var qcrao = Person(Student{age: 18})

    iface := (*iface)(unsafe.Pointer(&qcrao))
    fmt.Printf("iface.tab.hash = %#x\n", iface.tab.hash)
}

接口转换原理
当判定一种类型是否满足某个接口时，Go使用类型的方法集和接口所需要的方法进行匹配，如果类型的方法集完全包含接口的方法集，则可认为该类型实现了该接口。
Go会对方法集的函数按照函数名的字典序进行排序，实际的时间复杂度会由O(mn)降为O(m+n)。
// 将一个interface转换成另一个interface
func convI2I(inter *interfacetype, i iface) (r iface) {
    tab := i.tab
    if tab == nil {
        return
    }
    if tab.inter == inter {
        r.tab = tab
        r.data = i.data
        return
    }
    r.tab = getitab(inter, tab._type, false)
    r.data = i.data
    return
}

func getitab(inter *interfacetype, typ *_type, canfail bool) *itab {
    if len(inter.mhdr) == 0 {
        throw("internal error - misuse of itab")
    }

    // easy case
    if typ.tflag&tflagUncommon == 0 {
        // 判断是否可以失败
        if canfail {
            return nil
        }
        // 不可以则触发panic
        name := inter.typ.nameOff(inter.mhdr[0].name)
        panic(&TypeAssertionError{nil, typ, &inter.typ, name.name()})
    }

    var m *itab

    // First, look in the existing table to see if we can find the itab we need.
    // This is by far the most common case, so do it without locks.
    // Use atomic to ensure we see any previous writes done by the thread
    // that updates the itabTable field (with atomic.Storep in itabAdd).
    // 优先从tab表中寻找需要的itab
    t := (*itabTableType)(atomic.Loadp(unsafe.Pointer(&itabTable)))
    if m = t.find(inter, typ); m != nil {
        goto finish
    }

    // Not found.  Grab the lock and try again.
    // 没找到，获取锁再尝试一次
    lock(&itabLock)
    if m = itabTable.find(inter, typ); m != nil {
        unlock(&itabLock)
        goto finish
    }

    // Entry doesn't exist yet. Make a new entry & add it.
    // 还是没有，创建一个加入到全局表中
    m = (*itab)(persistentalloc(unsafe.Sizeof(itab{})+uintptr(len(inter.mhdr)-1)*goarch.PtrSize, 0, &memstats.other_sys))
    m.inter = inter
    m._type = typ
    // The hash is used in type switches. However, compiler statically generates itab's
    // for all interface/type pairs used in switches (which are added to itabTable
    // in itabsinit). The dynamically-generated itab's never participate in type switches,
    // and thus the hash is irrelevant.
    // Note: m.hash is _not_ the hash used for the runtime itabTable hash table.
    m.hash = 0
      // 填充函数列表并检查是否实现接口
