2）Go运行时处理
为了支持从系统给运行时传递参数，Go程序在进行引导时将对这部分参数进行处理。程序刚刚启动时，栈指针SP的前两个值分别对应argc和argv，分别存储参数的数量和具体的参数的值。
// src/runtime/asm_amd64.s
TEXT _rt0_amd64(SB),NOSPLIT,$-8
    MOVQ    0(SP), DI    // argc
    LEAQ    8(SP), SI    // argv
    JMP    runtime·rt0_go(SB)

TEXT runtime·rt0_go(SB),NOSPLIT,$0
    // 将参数向前复制到一个偶数栈上
    MOVQ    DI, AX            // argc
    MOVQ    SI, BX            // argv
    SUBQ    $(4*8+7), SP    // 2args 2auto
    ANDQ    $~15, SP
    MOVQ    AX, 16(SP)
    MOVQ    BX, 24(SP)

    // 初始化 g0 执行栈
    MOVQ    $runtime·g0(SB), DI            // DI = g0
    LEAQ    (-64*1024+104)(SP), BX
    MOVQ    BX, g_stackguard0(DI)        // g0.stackguard0 = SP + (-64*1024+104)
    MOVQ    BX, g_stackguard1(DI)        // g0.stackguard1 = SP + (-64*1024+104)
    MOVQ    BX, (g_stack+stack_lo)(DI)    // g0.stack.lo    = SP + (-64*1024+104)
    MOVQ    SP, (g_stack+stack_hi)(DI)    // g0.stack.hi    = SP

    // 确定 CPU 处理器的信息
    MOVL    $0, AX
    CPUID            // CPUID 会设置 AX 的值
    MOVL    AX, SI
2、线程本地存储TLS
之后会初始化并运行本地线程存储。
TEXT runtime·rt0_go(SB),NOSPLIT,$0
    (...)
#ifdef GOOS_darwin
    JMP ok // 在 Darwin 系统上跳过 TLS 设置
#endif

    LEAQ    runtime·m0+m_tls(SB), DI    // DI = m0.tls
    CALL    runtime·settls(SB)            // 将 TLS 地址设置到 DI

    // 使用它进行存储，确保能正常运行
    MOVQ    TLS, BX
    MOVQ    $0x123, g(BX)
    MOVQ    runtime·m0+m_tls(SB), AX
    CMPQ    AX, $0x123            // 判断 TLS 是否设置成功
    JEQ 2(PC)                     // 如果相等则向后跳转两条指令
    CALL    runtime·abort(SB)    // 使用 INT 指令执行中断
ok:
    // 程序刚刚启动，此时位于主线程
    // 当前栈与资源保存在 g0
    // 该线程保存在 m0
    MOVQ    TLS, BX
    LEAQ    runtime·g0(SB), CX
    MOVQ    CX, g(BX)
    LEAQ    runtime·m0(SB), AX

    MOVQ    CX, m_g0(AX) // m->g0 = g0
    MOVQ    AX, g_m(CX)  // g0->m = m0
    (...)
其中g0和m0是一组全局变量，在程序运行之初就已经存在了，除了程序参数外，会首先将m0与g0通过指针互相关联。
// set tls base to DI
TEXT runtime·settls(SB),NOSPLIT,$32
#ifdef GOOS_android
    // Android stores the TLS offset in runtime·tls_g.
    SUBQ    runtime·tls_g(SB), DI
#else
    ADDQ    $8, DI    // ELF wants to use -8(FS)
#endif
    MOVQ    DI, SI
    MOVQ    $0x1002, DI    // ARCH_SET_FS
    // SYS_arch_prctl 系统调用用来在x86_64上设置和获取架构相关特性
    // 它通过设置FS和GS寄存器来支持线程局部存储
    // FS寄存器：通常用于指向线程局部存储区的指针
    // GS寄存器：在windows中和FS差不多，在linux中主要用于存储指向进程控制块或其他内核数据的指针
    MOVQ    $SYS_arch_prctl, AX
    SYSCALL
    CMPQ    AX, $0xfffffffffffff001  // 验证是否成功
    JLS    2(PC)
    MOVL    $0xf1, 0xf1  // crash 崩溃
    RET
3、早期校验和系统级初始化
在正式初始化运行时组件之前，还需要做一些校验和系统级的初始化工作，包括运行时类型检查，系统参数的获取以及影响内存管理和程序调度的相关常量的初始化。
注意：Linux的可执行文件大多数是ELF格式，macOS的可执行文件大多数是mach-o格式，两者存在很大区别，windows系统区别更大。
1）运行时类型检查
本质上属于对编译器翻译工作的一个校验。
// runtime/runtime1.go
// 程序启动时的类型检查函数
func check() {
    var (
        a     int8
        b     uint8
        c     int16
        d     uint16
        e     int32
        f     uint32
        g     int64
        h     uint64
        i, i1 float32
        j, j1 float64
        k     unsafe.Pointer
        l     *uint16
        m     [4]byte
    )
    type x1t struct {
        x uint8
    }
    type y1t struct {
        x1 x1t
        y  uint8
    }
    var x1 x1t
    var y1 y1t

    // 校验各个类型的大小是否符合预期
    if unsafe.Sizeof(a) != 1 {
        throw("bad a")
    }
    if unsafe.Sizeof(b) != 1 {
        throw("bad b")
    }
    if unsafe.Sizeof(c) != 2 {
        throw("bad c")
    }
    if unsafe.Sizeof(d) != 2 {
        throw("bad d")
    }
    if unsafe.Sizeof(e) != 4 {
        throw("bad e")
    }
    if unsafe.Sizeof(f) != 4 {
        throw("bad f")
    }
    if unsafe.Sizeof(g) != 8 {
        throw("bad g")
    }
    if unsafe.Sizeof(h) != 8 {
        throw("bad h")
    }
    if unsafe.Sizeof(i) != 4 {
        throw("bad i")
    }
    if unsafe.Sizeof(j) != 8 {
        throw("bad j")
    }
    if unsafe.Sizeof(k) != goarch.PtrSize {
        throw("bad k")
    }
    if unsafe.Sizeof(l) != goarch.PtrSize {
        throw("bad l")
    }
    if unsafe.Sizeof(x1) != 1 {
        throw("bad unsafe.Sizeof x1")
    }
    if unsafe.Offsetof(y1.y) != 1 {
        throw("bad offsetof y1.y")
    }
    if unsafe.Sizeof(y1) != 2 {
        throw("bad unsafe.Sizeof y1")
    }

    // timediv函数测试
    // 假设timediv函数用于计算秒和纳秒部分，并返回秒部分，同时通过指针参数返回纳秒部分
    if timediv(12345*1000000000+54321, 1000000000, &e) != 12345 || e != 54321 {
        throw("bad timediv")
    }

    // 测试原子操作
    var z uint32
    z = 1
    if !atomic.Cas(&z, 1, 2) {
        throw("cas1")
    }
    if z != 2 {
        throw("cas2")
    }

    z = 4
    if atomic.Cas(&z, 5, 6) {
        throw("cas3")
    }
    if z != 4 {
        throw("cas4")
    }

    z = 0xffffffff
    if !atomic.Cas(&z, 0xffffffff, 0xfffffffe) {
        throw("cas5")
    }
    if z != 0xfffffffe {
        throw("cas6")
    }

    m = [4]byte{1, 1, 1, 1}
    atomic.Or8(&m[1], 0xf0)
    if m[0] != 1 || m[1] != 0xf1 || m[2] != 1 || m[3] != 1 {
        throw("atomicor8")
    }

    m = [4]byte{0xff, 0xff, 0xff, 0xff}
    atomic.And8(&m[1], 0x1)
    if m[0] != 0xff || m[1] != 0x1 || m[2] != 0xff || m[3] != 0xff {
        throw("atomicand8")
    }

    // 浮点数NaN检查
    // NaN表示未定义或不可表示的值，用于处理无效的浮点运算结果
    *(*uint64)(unsafe.Pointer(&j)) = ^uint64(0)
    if j == j {
        throw("float64nan")
    }
    if !(j != j) {
        throw("float64nan1")
    }

    *(*uint64)(unsafe.Pointer(&j1)) = ^uint64(1)
    if j == j1 {
        throw("float64nan2")
    }
    if !(j != j1) {
        throw("float64nan3")
    }

    *(*uint32)(unsafe.Pointer(&i)) = ^uint32(0)
    if i == i {
        throw("float32nan")
    }
    if i == i {
        throw("float32nan1")
    }

    *(*uint32)(unsafe.Pointer(&i1)) = ^uint32(1)
    if i == i1 {
        throw("float32nan2")
    }
    if i == i1 {
        throw("float32nan3")
    }

    // 其他检查
    testAtomic64()

    if _FixedStack != round2(_FixedStack) {
        throw("FixedStack is not power-of-2")
    }

    if !checkASM() {
        throw("assembly checks failed")
    }
}

